mapper.select:
/* selectWpasmaList */ SELECT PASTRMD AS ROWKEY, PASTRMD, PASTRNM, PASTRTG, PASTROD, PAUSEYN, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER, UPDTCHK FROM ${userInfo.schema}.WPASMA
AND PASTRMD LIKE UPPER(CONCAT('%', #{param.pastrmd}, '%'))
AND PASTRNM like UPPER(CONCAT('%', #{param.pastrnm}, '%'))
AND PAUSEYN = #{param.pauseyn}
ORDER BY PASTROD

/* selectWpashdList */ SELECT CONCAT(HD.WAREKEY, HD.PASTRKY) AS ROWKEY, HD.WAREKEY, HD.PASTRKY, WA.WHNAMLC, HD.PASTRNM, HD.PAUSEYN, HD.CREDATE, HD.CRETIME, HD.CREUSER, HD.LMODATE, HD.LMOTIME, HD.LMOUSER, HD.UPDTCHK FROM ${userInfo.schema}.WPASHD HD INNER JOIN ${userInfo.schema}.MWARMA WA ON( HD.WAREKEY = WA.WAREKEY )
AND HD.WAREKEY = #{param.warekey}
AND HD.PASTRKY LIKE UPPER(CONCAT('%', #{param.pastrky}, '%'))
AND HD.PASTRNM like UPPER(CONCAT('%', #{param.pastrnm}, '%'))
AND HD.PAUSEYN = #{param.pauseyn}
ORDER BY HD.WAREKEY, HD.PASTRKY

/* selectWpasitList */
SELECT
	CONCAT(IT.WAREKEY, IT.PASTRKY, IT.PASTRIT) AS ROWKEY,
	IT.WAREKEY, IT.PASTRKY, IT.PASTRIT,
	IT.PASTRMD, IT.PASTRWG, IT.PASTRST, IT.PAESTYN, IT.PAUSEYN,
	WA.WHNAMLC, PM.PASTRNM, PM.PASTRTG,
	IT.CREDATE, IT.CRETIME, IT.CREUSER, IT.LMODATE, IT.LMOTIME,
	IT.LMOUSER, IT.UPDTCHK
FROM
	${userInfo.schema}.WPASIT IT
	INNER JOIN ${userInfo.schema}.MWARMA WA ON(
		IT.WAREKEY = WA.WAREKEY
	)
	INNER JOIN ${userInfo.schema}.WPASHD HD ON(
		IT.WAREKEY = HD.WAREKEY AND IT.PASTRKY = HD.PASTRKY
	)
	INNER JOIN ${userInfo.schema}.WPASMA PM ON(
		IT.PASTRMD = PM.PASTRMD
	)


	AND IT.WAREKEY = #{param.warekey}


	AND IT.PASTRKY = #{param.pastrky}


	AND IT.PAUSEYN = #{param.pauseyn}


ORDER BY IT.PASTRKY, IT.PASTRIT

/* selectWpaord */
SELECT

	OD.WAREKEY, OD.DOCCATE, OD.DOCTYPE,

	OD.PASTRKY, OD.PAUSEYN
FROM
	${userInfo.schema}.WPAORD OD
	INNER JOIN ${userInfo.schema}.MWARMA WA ON(
		OD.WAREKEY = WA.WAREKEY
	)
	INNER JOIN ${userInfo.schema}.MDOCMA DO ON(
		DO.WAREKEY = WA.WAREKEY
		AND OD.DOCCATE = DO.DOCCATE
		AND OD.DOCTYPE = DO.DOCTYPE
	)
	INNER JOIN ${userInfo.schema}.WPASHD HD ON(
		OD.WAREKEY = HD.WAREKEY
		AND OD.PASTRKY = HD.PASTRKY
	)
WHERE OD.WAREKEY = #{param.warekey}
AND OD.DOCCATE = #{param.doccate}
AND OD.DOCTYPE = #{param.doctype}
AND OD.PAUSEYN = 'Y'

/* selectWpaordList */ SELECT CONCAT(OD.WAREKEY, OD.DOCCATE, DO.DOCCTNM ) AS ROWKEY,
OD.WAREKEY, OD.DOCCATE, OD.DOCTYPE,
WA.WHNAMLC, DO.DOCCTNM, DO.DOCTYNM, OD.PASTRKY, OD.PAUSEYN,
OD.CREDATE, OD.CRETIME, OD.CREUSER, OD.LMODATE, OD.LMOTIME, OD.LMOUSER, OD.UPDTCHK FROM ${userInfo.schema}.WPAORD OD INNER JOIN ${userInfo.schema}.MWARMA WA ON( OD.WAREKEY = WA.WAREKEY ) INNER JOIN ${userInfo.schema}.MDOCMA DO ON( DO.WAREKEY = WA.WAREKEY AND OD.DOCCATE = DO.DOCCATE AND OD.DOCTYPE = DO.DOCTYPE ) INNER JOIN ${userInfo.schema}.WPASHD HD ON( OD.WAREKEY = HD.WAREKEY AND OD.PASTRKY = HD.PASTRKY )
AND OD.WAREKEY = #{param.warekey}
AND OD.PASTRKY LIKE UPPER(CONCAT('%', #{param.pastrky}, '%'))
AND OD.DOCCATE = #{param.doccate}
AND OD.DOCTYPE = #{param.doctype}
AND OD.PAUSEYN = #{param.pauseyn}
ORDER BY OD.WAREKEY, OD.DOCCATE, OD.DOCTYPE

/* selectWpaordWithWpasit */ SELECT
WPI.WAREKEY, WPI.PASTRKY, WPI.PASTRIT,
WPI.PASTRMD, WPI.PASTRST, WPI.PASTRWG, WPI.PAESTYN,
WPM.PASTRNM AS PASTRNM,
WPH.PASTRNM AS PASTHNM,
WPO.DOCCATE, WPO.DOCTYPE FROM ${userInfo.schema}.WPASIT WPI INNER JOIN ${userInfo.schema}.WPASHD WPH ON WPH.PASTRKY = WPI.PASTRKY AND WPH.WAREKEY = WPI.WAREKEY INNER JOIN ${userInfo.schema}.WPASMA WPM ON WPM.PASTRMD = WPI.PASTRMD INNER JOIN ${userInfo.schema}.WPAORD WPO ON WPO.PASTRKY = WPI.PASTRKY AND WPO.WAREKEY = WPI.WAREKEY WHERE WPI.PAUSEYN = 'Y' AND WPH.PAUSEYN = 'Y' AND WPM.PAUSEYN = 'Y' AND WPO.PAUSEYN = 'Y' AND WPI.WAREKEY = #{param.warekey} AND WPO.DOCCATE = #{param.doccate} AND WPO.DOCTYPE = #{param.doctype}

mapper.update:
/* updateWpaordList */

UPDATE ${userInfo.schema}.WPAORD
	SET
		PASTRKY = #{item.pastrky},
		PAUSEYN = #{item.pauseyn},
		LMODATE = date_format(NOW(),'%Y%m%d'),
		LMOTIME = date_format(NOW(),'%H%i%s'),
		LMOUSER = #{userInfo.useract},
		UPDTCHK = #{item.updtchk} + 1
	WHERE
		WAREKEY = #{item.warekey}
		AND DOCCATE = #{item.doccate}
		AND DOCTYPE = #{item.doctype}

mapper.select:
/* selectLocationListForStoreStrategy */ SELECT
MLO.WAREKEY, MLO.AREAKEY, MLO.LOCAKEY,
MLO.LOCSTAT, MLO.LOCTYPE, MLO.SIZEPRI, MLO.BTRCPRI, MLO.ITDTPRI, MLO.CUSTPRI, MLO.REGIPRI, MLO.DESTPRI, MLO.INBOPRI, MLO.LOUSEYN, MLO.LOCANAM,
MAR.AREANAM, MEQ1.EQUIPKY, MEQ2.LOCAKEY AS ULLOCKY, MEQ2.LOCANAM AS ULLOCNM, COUNT(WST.SKUMKEY) AS STOCKCNT,
( SELECT COUNT(W2.SKUMKEY) FROM ${userInfo.schema}.WTAKIT W2 WHERE W2.WAREKEY = MLO.WAREKEY AND W2.FRAREKY = MLO.AREAKEY AND W2.FRLOCKY = MLO.LOCAKEY AND W2.TASKSTS IN ('NEW', 'ING', 'OPERCMP') AND W2.MVSTDAT >= date_format(NOW(),'%H%i%s') AND W2.MVSTDAT <= date_format(NOW(),'%H%i%s') AND DATE_FORMAT(STR_TO_DATE(W2.MVSTTIM, '%H%i%s'), '%H%i%s') = date_format(NOW(),'%Y%m%d') ) AS TASKCNT, ( SELECT COUNT(A1.SKUMKEY) FROM ${userInfo.schema}.WASNIT A1 INNER JOIN ${userInfo.schema}.WASNHD A2 ON A1.EOASNKY = A2.EOASNKY AND A1.WAREKEY = A2.WAREKEY WHERE A2.ASNSTAT IN ('NEW', 'ACONF', 'PCONF', 'ING') AND A1.ASNITST IN ('NEW', 'CONF', 'ING') AND A1.WAREKEY = MLO.WAREKEY AND A1.TOAREKY = MLO.AREAKEY AND A1.TOLOCKY = MLO.LOCAKEY AND DATE_FORMAT(STR_TO_DATE(A2.ASNDATE, '%H%i%s'), '%H%i%s') = date_format(NOW(),'%Y%m%d') ) AS ASNCNT,
( INBOPRI
+ IF(#{param.skugrky} = MLO.SIZEPRI, #{strategy.pastrwg} , 0)
+ IF(#{param.ownerky} = MLO.CUSTPRI, #{strategy.pastrwg} , 0)
+ IF(#{param.regimod} = MLO.REGIPRI, #{strategy.pastrwg} , 0)
+ IF(#{param.btrcate} = MLO.BTRCPRI, #{strategy.pastrwg} , 0)
+ IF(#{param.itemcod} = MLO.ITDTPRI, #{strategy.pastrwg} , 0)
+ IF(#{param.destmod} = MLO.DESTPRI, #{strategy.pastrwg} , 0)
- (COUNT(WST.SKUMKEY) / 10) * (#{strategy.pastrwg})
+ IF(( SELECT COUNT(W2.SKUMKEY) FROM ${userInfo.schema}.WTAKIT W2 WHERE W2.WAREKEY = MLO.WAREKEY AND W2.FRAREKY = MLO.AREAKEY AND W2.FRLOCKY = MLO.LOCAKEY AND W2.TASKSTS IN ('NEW', 'ING', 'OPERCMP') AND DATE_FORMAT(STR_TO_DATE(W2.MVSTTIM, '%H%i%s'), '%H%i%s') = date_format(NOW(),'%Y%m%d') ) = 0, #{strategy.pastrwg}, 0) + IF(( SELECT COUNT(A1.SKUMKEY) FROM ${userInfo.schema}.WASNIT A1 INNER JOIN ${userInfo.schema}.WASNHD A2 ON A1.EOASNKY = A2.EOASNKY AND A1.WAREKEY = A2.WAREKEY WHERE A2.ASNSTAT IN ('NEW', 'ACONF', 'PCONF', 'ING') AND A1.ASNITST IN ('NEW', 'CONF', 'ING') AND A1.WAREKEY = MLO.WAREKEY AND A1.TOAREKY = MLO.AREAKEY AND A1.TOLOCKY = MLO.LOCAKEY AND DATE_FORMAT(STR_TO_DATE(A2.ASNDATE, '%H%i%s'), '%H%i%s') = date_format(NOW(),'%Y%m%d') ) = 0, #{strategy.pastrwg}, 0)
) AS PRIORITY_SCORE
FROM ${userInfo.schema}.MLOCMA MLO INNER JOIN ${userInfo.schema}.MWARMA MWA ON( MWA.WAREKEY = MLO.WAREKEY ) INNER JOIN ${userInfo.schema}.MAREMA MAR ON( MAR.WAREKEY = MLO.WAREKEY AND MAR.AREAKEY = MLO.AREAKEY ) INNER JOIN ( SELECT A.WAREKEY, A.AREAKEY, A.EQUIPKY, A.LOCAKEY, A.MANEQYN, A.ELUSEYN, B.EQUSTAT FROM ${userInfo.schema}.MEQLOC A INNER JOIN ${userInfo.schema}.MEQUMA B ON( A.WAREKEY = B.WAREKEY AND A.AREAKEY = B.AREAKEY AND A.EQUIPKY = B.EQUIPKY ) WHERE A.ELUSEYN = 'Y' AND B.EQUSEYN = 'Y' AND B.EQUSTAT = 'NORMAL' GROUP BY A.WAREKEY, A.AREAKEY, A.EQUIPKY, A.LOCAKEY, A.MANEQYN, A.ELUSEYN, B.EQUSTAT ORDER BY A.MANEQYN DESC ) AS MEQ1 ON( MEQ1.WAREKEY = MLO.WAREKEY AND MEQ1.AREAKEY = MLO.AREAKEY AND MEQ1.LOCAKEY = MLO.LOCAKEY ) INNER JOIN ( SELECT M1.WAREKEY, M1.AREAKEY, M1.EQUIPKY, M1.LOCAKEY, M1.MANEQYN, M1.ELUSEYN, M2.LOCTYPE, M2.LOUSEYN, M2.LOCANAM FROM ${userInfo.schema}.MEQLOC M1 INNER JOIN ${userInfo.schema}.MLOCMA M2 ON ( M1.WAREKEY = M2.WAREKEY AND M1.AREAKEY = M2.AREAKEY AND M1.LOCAKEY = M2.LOCAKEY ) INNER JOIN ${userInfo.schema}.MEQUMA M3 ON( M1.WAREKEY = M3.WAREKEY AND M1.AREAKEY = M3.AREAKEY AND M1.EQUIPKY = M3.EQUIPKY ) WHERE M1.ELUSEYN = 'Y' AND M2.LOCTYPE = 'STP' AND M2.LOUSEYN = 'Y' AND M3.EQUSEYN = 'Y' AND M3.EQUSTAT = 'NORMAL' GROUP BY M1.WAREKEY, M1.AREAKEY, M1.EQUIPKY, M1.LOCAKEY, M1.MANEQYN, M1.ELUSEYN, M2.LOCTYPE, M2.LOUSEYN, M2.LOCANAM ORDER BY M1.WAREKEY, M1.AREAKEY, M1.LOCAKEY, M1.EQUIPKY, M1.MANEQYN DESC ) AS MEQ2 ON( MEQ2.WAREKEY = MLO.WAREKEY ) LEFT JOIN ${userInfo.schema}.WSTKKY WST ON WST.WAREKEY = MLO.WAREKEY AND WST.AREAKEY = MLO.AREAKEY AND WST.LOCAKEY = MLO.LOCAKEY WHERE MLO.LOCSTAT = 'NORMAL' AND MWA.WHUSEYN = 'Y' AND MAR.ARUSEYN = 'Y' AND MLO.LOUSEYN = 'Y' AND MEQ1.ELUSEYN = 'Y' AND MEQ1.EQUSTAT = 'NORMAL' AND MLO.LOCTYPE = 'BED' AND MEQ2.EQUIPKY = MEQ1.EQUIPKY AND MLO.WAREKEY = #{param.warekey}
AND MLO.SIZEPRI = #{param.skugrky}
AND MLO.CUSTPRI = #{param.ownerky}
AND MLO.REGIPRI = #{param.regimod}
AND MLO.DESTPRI = #{param.destmod}
AND MLO.BTRCPRI = #{param.btrcate}
AND MLO.ITDTPRI = #{param.itemcod}
GROUP BY MLO.WAREKEY, MLO.AREAKEY, MLO.LOCAKEY,
MLO.LOCSTAT, MLO.LOCTYPE, MLO.SIZEPRI, MLO.BTRCPRI, MLO.ITDTPRI, MLO.CUSTPRI, MLO.REGIPRI, MLO.DESTPRI, MLO.INBOPRI, MLO.LOUSEYN, MLO.LOCANAM,
MAR.AREANAM, MEQ1.EQUIPKY, MEQ2.LOCAKEY, MEQ2.LOCANAM
AND STOCKCNT < 50
AND TASKCNT = 0 AND ASNCNT = 0
, PRIORITY_SCORE DESC , MEQ2.MANEQYN DESC
, STOCKCNT ${strategy.pastrst}
, MLO.SIZEPRI ${strategy.pastrst}
, MLO.CUSTPRI ${strategy.pastrst}
, MLO.REGIPRI ${strategy.pastrst}
, MLO.BTRCPRI ${strategy.pastrst}
, MLO.ITDTPRI ${strategy.pastrst}
, MLO.SIZEPRI ${strategy.pastrst}
, TASKCNT ${strategy.pastrst} , ASNCNT ${strategy.pastrst}
